import{_ as e,o as i,c as o,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F16_大股東成本與籌碼結構審計.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F16_大股東成本與籌碼結構審計.md"}'),r={name:"審計報告庫/財務審計/6239_力成/20260617/F16_大股東成本與籌碼結構審計.md"};function l(n,a,h,s,d,c){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="f16-大股東成本與籌碼結構審計-財務審計專家報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 財務審計專家報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-財務審計專家報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：千張大股東持股70.8%、外資38.3%；董監事含Kioxia&gt;30%且0質押。超豐持有庫藏股2.7%（成本173元），屬公司派高度主導型。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年12月最新股權分散表</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>股權分散顯示極度集中：千張以上大股東95人持有70.78%股權（5.37億股），400張以上大股東合計180人約佔78%。散戶（1-999股）46,829人僅持0.41%。外資持股38.3%（2025年底），較年初~34%略增。董監事持股：年報揭露及子公司持股，超豐持力成20,350張（2.7%，視同庫藏），Kioxia為法人董事。無董監質押記錄。子公司持有庫藏股（超豐持20,350張，成本約173元/股，市值35.2億）提供股價下檔支撐。GDR已於2024年終止上市，籌碼結構簡化。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="籌碼集中度分析" tabindex="-1">籌碼集中度分析 <a class="header-anchor" href="#籌碼集中度分析" aria-label="Permalink to &quot;籌碼集中度分析&quot;">​</a></h3><p>力成的籌碼極度集中於大股東（千張以上70.8%），散戶佔比僅0.41%，在上市櫃公司中屬極低散戶參與度的類型。400-600張級別44人（2.81%）、600-800張22人（2.01%）、800-1000張19人（2.22%），分層均勻，無單一超大股東（Kioxia約17-19%推估，法人董事持股分散）。此結構的意義：股價不易被散戶情緒左右，波動性相對低，但也代表籌碼流動性較差。</p><h3 id="質押風險評估" tabindex="-1">質押風險評估 <a class="header-anchor" href="#質押風險評估" aria-label="Permalink to &quot;質押風險評估&quot;">​</a></h3><p>年報及公開資訊顯示力成董監事無質押記錄。子公司超豐持有庫藏股20,350張（視同庫藏股票，依公司法規定），為子公司長期投資非融資質押。整體股權無質押平倉風險，財務結構穩健。</p><h3 id="大股東成本估算" tabindex="-1">大股東成本估算 <a class="header-anchor" href="#大股東成本估算" aria-label="Permalink to &quot;大股東成本估算&quot;">​</a></h3><p>力成近5年股價區間約80-200元。Kioxia身為長期法人董事（10年以上），取得成本推估低於100元。子公司超豐持有成本173元/股（按2025年底帳面金額/20,350張=173元），高於當前股價可能帶來的帳面損失已反映在合併報表中（透過其他綜合損益）。無近期增減持公告，籌碼變動主要來自外資進出。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>外資持股波動影響股價</strong>：外資持股從34%至38%波動，1-2月的週轉顯示外資曾單週減持約2.5%（約1,900萬股）。力成外資持股比在半導體封測中屬中等（日月光&gt;60%），若全球半導體循環轉向，外資大舉撤離可能造成顯著賣壓。</li><li><strong>大股東高度集中潛在流動性風險</strong>：千張以上佔70.8%，實際在外流通籌碼僅約22萬張，日均成交量若僅數千張，大額交易將顯著影響股價。此結構對大型法人進出較不友善。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>公司派高度主導的穩定籌碼</strong>：大股東持股70.8%且0質押，不存在斷頭賣壓。子公司超豐持有庫藏股2.7%（成本173元），在公司派眼中當前股價低估時有護盤財力。</li><li><strong>GDR終止消除海外賣壓</strong>：2024年終止盧森堡GDR上市，減少海外籌碼對台股的潛在套利賣壓。2025年外資持股從34%增至38%，顯示外資實際加碼而非撤離。</li><li><strong>Kioxia的策略性持股具長期穩定性</strong>：Kioxia身為法人董事且為最大客戶，持股非財務性投資而是策略性供應鏈整合，短期內無出售動機。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>力成的股權結構屬穩健保守型（大股東高度集中、0質押、子公司庫藏股護盤）。主要風險不是股權惡化，而是流通籌碼少導致股價波動受外資進出影響。長期來看，公司派主導的結構對長期股東保護力佳。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (backer_holding 6239, holding 6239)</li><li>原始數據：FinMind TaiwanStockShareholdingSpread、TaiwanStockHolding</li><li>查詢參數：stock_id=6239, start=2025-12-01, end=2026-01-12</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 48、51，股權及庫藏股)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const b=e(r,[["render",l]]);export{u as __pageData,b as default};
